import React, { useEffect, useMemo, useState } from "react";
import "./styles.css";

import Modal from "./components/Modal";
import AssetForm from "./components/AssetForm";
import IncidentForm from "./components/IncidentForm";
import TenantForm from "./components/TenantForm";

const ASSET_API = "http://localhost:5001";
const INCIDENT_API = "http://localhost:5002";
const TENANT_API = "http://localhost:5003";

function App() {
  const [tenantId, setTenantId] = useState("");
  const [tenants, setTenants] = useState([]);
  const [assets, setAssets] = useState([]);
  const [incidents, setIncidents] = useState([]);

  const [loadingTenants, setLoadingTenants] = useState(false);
  const [loadingAssets, setLoadingAssets] = useState(false);
  const [loadingIncidents, setLoadingIncidents] = useState(false);

  const [showTenantModal, setShowTenantModal] = useState(false);
  const [showAssetModal, setShowAssetModal] = useState(false);
  const [showIncidentModal, setShowIncidentModal] = useState(false);

  const [editingTenant, setEditingTenant] = useState(null);
  const [editingAsset, setEditingAsset] = useState(null);
  const [editingIncident, setEditingIncident] = useState(null);

  const selectedTenant = useMemo(() => {
    return tenants.find((t) => String(t.id) === String(tenantId)) || null;
  }, [tenants, tenantId]);

  const totalAssets = assets.length;
  const totalIncidents = incidents.length;
  const highIncidents = incidents.filter(
    (i) => (i.severity || "").toLowerCase() === "high"
  ).length;
  const totalTenants = tenants.length;

  const getTenantIdQuery = () => `tenantId=${encodeURIComponent(tenantId)}`;

  const fetchTenants = async () => {
    try {
      setLoadingTenants(true);
      const res = await fetch(`${TENANT_API}/tenants`);
      const data = await res.json();

      const tenantList = Array.isArray(data) ? data : [];
      setTenants(tenantList);

      if (tenantList.length > 0) {
        const stillExists = tenantList.some(
          (t) => String(t.id) === String(tenantId)
        );

        if (!tenantId || !stillExists) {
          setTenantId(String(tenantList[0].id));
        }
      } else {
        setTenantId("");
      }
    } catch (err) {
      console.error("Failed to fetch tenants:", err);
      setTenants([]);
    } finally {
      setLoadingTenants(false);
    }
  };

  const fetchAssets = async () => {
    if (!tenantId) {
      setAssets([]);
      return;
    }

    try {
      setLoadingAssets(true);
      const res = await fetch(`${ASSET_API}/assets?${getTenantIdQuery()}`);
      const data = await res.json();
      setAssets(Array.isArray(data) ? data : []);
    } catch (err) {
      console.error("Failed to fetch assets:", err);
      setAssets([]);
    } finally {
      setLoadingAssets(false);
    }
  };

  const fetchIncidents = async () => {
    if (!tenantId) {
      setIncidents([]);
      return;
    }

    try {
      setLoadingIncidents(true);
      const res = await fetch(`${INCIDENT_API}/incidents?${getTenantIdQuery()}`);
      const data = await res.json();
      setIncidents(Array.isArray(data) ? data : []);
    } catch (err) {
      console.error("Failed to fetch incidents:", err);
      setIncidents([]);
    } finally {
      setLoadingIncidents(false);
    }
  };

  useEffect(() => {
    fetchTenants();
  }, []);

  useEffect(() => {
    if (tenantId) {
      fetchAssets();
      fetchIncidents();
    } else {
      setAssets([]);
      setIncidents([]);
    }
  }, [tenantId]);

  const getAssetTypeClass = (type) => {
    const value = (type || "").toLowerCase();
    if (value === "vm") return "type-pill type-vm";
    if (value === "db") return "type-pill type-db";
    if (value === "switch") return "type-pill type-switch";
    return "type-pill";
  };

  const getSeverityClass = (severity) => {
    const value = (severity || "").toLowerCase();
    if (value === "high") return "severity-badge severity-high";
    if (value === "medium") return "severity-badge severity-medium";
    if (value === "low") return "severity-badge severity-low";
    return "severity-badge";
  };

  const getAssetNameById = (assetId) => {
    const asset = assets.find((a) => String(a.id) === String(assetId));
    return asset ? asset.name : "Unknown Asset";
  };

  const handleDeleteAsset = async (asset) => {
    const confirmed = window.confirm(`Delete asset "${asset.name}"?`);
    if (!confirmed) return;

    try {
      const res = await fetch(`${ASSET_API}/assets/${asset.id}?${getTenantIdQuery()}`, {
        method: "DELETE",
      });

      if (!res.ok) {
        throw new Error("Failed to delete asset");
      }

      fetchAssets();
      fetchIncidents();
    } catch (err) {
      console.error(err);
      alert("Failed to delete asset");
    }
  };

  const handleDeleteIncident = async (incident) => {
    const confirmed = window.confirm(
      `Delete incident "${incident.description || incident.title || incident.id}"?`
    );
    if (!confirmed) return;

    try {
      const res = await fetch(
        `${INCIDENT_API}/incidents/${incident.id}?${getTenantIdQuery()}`,
        {
          method: "DELETE",
        }
      );

      if (!res.ok) {
        throw new Error("Failed to delete incident");
      }

      fetchIncidents();
    } catch (err) {
      console.error(err);
      alert("Failed to delete incident");
    }
  };

  const handleDeleteTenant = async (tenant) => {
    const confirmed = window.confirm(`Delete tenant "${tenant.name}"?`);
    if (!confirmed) return;

    try {
      const res = await fetch(`${TENANT_API}/tenants/${tenant.id}`, {
        method: "DELETE",
      });

      if (!res.ok) {
        throw new Error("Failed to delete tenant");
      }

      await fetchTenants();
      await fetchAssets();
      await fetchIncidents();
    } catch (err) {
      console.error(err);
      alert("Failed to delete tenant");
    }
  };

  return (
    <div className="app-shell">
      <div className="background-glow glow-one" />
      <div className="background-glow glow-two" />

      <div className="dashboard-container">
        <header className="topbar">
          <div className="topbar-left">
            <div className="eyebrow">Operations Platform</div>
            <h1 className="app-title">Multi-Tenant ITOM</h1>
            <p className="app-subtitle">
              Unified tenant, asset, and incident operations in one dashboard.
            </p>
          </div>

          <div className="topbar-right">
            <label className="tenant-selector-label">Active Tenant</label>
            <select
              className="tenant-selector"
              value={tenantId}
              onChange={(e) => setTenantId(e.target.value)}
              disabled={loadingTenants || tenants.length === 0}
            >
              {tenants.length === 0 ? (
                <option value="">No Tenants</option>
              ) : (
                tenants.map((tenant) => (
                  <option key={tenant.id} value={tenant.id}>
                    {tenant.name}
                  </option>
                ))
              )}
            </select>
          </div>
        </header>

        <section className="action-bar">
          <div className="action-bar-left">
            <button className="btn btn-primary" onClick={() => {
              setEditingTenant(null);
              setShowTenantModal(true);
            }}>
              + Tenant
            </button>

            <button
              className="btn btn-secondary"
              onClick={() => {
                setEditingAsset(null);
                setShowAssetModal(true);
              }}
              disabled={!tenantId}
            >
              + Asset
            </button>

            <button
              className="btn btn-secondary"
              onClick={() => {
                setEditingIncident(null);
                setShowIncidentModal(true);
              }}
              disabled={!tenantId}
            >
              + Incident
            </button>
          </div>

          <div className="action-bar-right">
            {selectedTenant ? (
              <div className="active-tenant-chip">
                <span className="status-dot" />
                {selectedTenant.name}
              </div>
            ) : (
              <div className="active-tenant-chip muted">No tenant selected</div>
            )}
          </div>
        </section>

        <section className="stats-grid">
          <div className="stat-card">
            <div className="stat-label">Total Assets</div>
            <div className="stat-value">{totalAssets}</div>
            <div className="stat-foot">Assets for active tenant</div>
          </div>

          <div className="stat-card">
            <div className="stat-label">Open Incidents</div>
            <div className="stat-value">{totalIncidents}</div>
            <div className="stat-foot">Incident records linked to tenant</div>
          </div>

          <div className="stat-card">
            <div className="stat-label">High Severity</div>
            <div className="stat-value">{highIncidents}</div>
            <div className="stat-foot">Needs faster action</div>
          </div>

          <div className="stat-card">
            <div className="stat-label">Tenants</div>
            <div className="stat-value">{totalTenants}</div>
            <div className="stat-foot">Onboarded in platform</div>
          </div>
        </section>

        <section className="panel">
          <div className="panel-header">
            <div>
              <h2 className="panel-title">Assets</h2>
              <p className="panel-subtitle">
                Infrastructure resources under the selected tenant.
              </p>
            </div>
          </div>

          {loadingAssets ? (
            <div className="empty-state">Loading assets...</div>
          ) : assets.length === 0 ? (
            <div className="empty-state">
              No assets found for this tenant. Add your first asset.
            </div>
          ) : (
            <div className="assets-grid">
              {assets.map((asset) => (
                <div className="asset-card" key={asset.id}>
                  <div className="asset-card-top">
                    <div>
                      <div className="asset-name">{asset.name}</div>
                      <div className="asset-id">ID: {asset.id}</div>
                    </div>

                    <span className={getAssetTypeClass(asset.type)}>
                      {asset.type || "UNKNOWN"}
                    </span>
                  </div>

                  <div className="asset-meta-row">
                    <span className="meta-label">Tenant</span>
                    <span className="meta-value">
                      {selectedTenant?.name || asset.tenantId || "-"}
                    </span>
                  </div>

                  <div className="asset-meta-row">
                    <span className="meta-label">Category</span>
                    <span className="meta-value">{asset.type || "-"}</span>
                  </div>

                  <div className="asset-meta-row">
                    <span className="meta-label">Status</span>
                    <span className="health-pill">Active</span>
                  </div>

                  <div className="card-actions">
                    <button
                      className="btn btn-ghost"
                      onClick={() => {
                        setEditingAsset(asset);
                        setShowAssetModal(true);
                      }}
                    >
                      Edit
                    </button>

                    <button
                      className="btn btn-danger"
                      onClick={() => handleDeleteAsset(asset)}
                    >
                      Delete
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </section>

        <section className="panel">
          <div className="panel-header">
            <div>
              <h2 className="panel-title">Incidents</h2>
              <p className="panel-subtitle">
                Operational issues linked to your tenant assets.
              </p>
            </div>
          </div>

          {loadingIncidents ? (
            <div className="empty-state">Loading incidents...</div>
          ) : incidents.length === 0 ? (
            <div className="empty-state">
              No incidents found for this tenant. Add your first incident.
            </div>
          ) : (
            <div className="incident-table">
              <div className="incident-table-head">
                <div>Issue</div>
                <div>Severity</div>
                <div>Asset</div>
                <div>Actions</div>
              </div>

              {incidents.map((incident) => (
                <div className="incident-row" key={incident.id}>
                  <div className="incident-main">
                    <div className="incident-title">
                      {incident.description || incident.title || "Untitled Incident"}
                    </div>
                    <div className="incident-id">ID: {incident.id}</div>
                  </div>

                  <div>
                    <span className={getSeverityClass(incident.severity)}>
                      {incident.severity || "Unknown"}
                    </span>
                  </div>

                  <div className="incident-asset-name">
                    {getAssetNameById(incident.assetId)}
                  </div>

                  <div className="incident-actions">
                    <button
                      className="btn btn-ghost"
                      onClick={() => {
                        setEditingIncident(incident);
                        setShowIncidentModal(true);
                      }}
                    >
                      Edit
                    </button>

                    <button
                      className="btn btn-danger"
                      onClick={() => handleDeleteIncident(incident)}
                    >
                      Delete
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </section>

        <section className="panel">
          <div className="panel-header">
            <div>
              <h2 className="panel-title">Tenants</h2>
              <p className="panel-subtitle">
                Manage onboarded tenants in the platform.
              </p>
            </div>
          </div>

          {loadingTenants ? (
            <div className="empty-state">Loading tenants...</div>
          ) : tenants.length === 0 ? (
            <div className="empty-state">
              No tenants available. Add your first tenant.
            </div>
          ) : (
            <div className="tenant-list">
              {tenants.map((tenant) => (
                <div
                  key={tenant.id}
                  className={`tenant-item ${
                    String(tenant.id) === String(tenantId) ? "tenant-item-active" : ""
                  }`}
                >
                  <div>
                    <div className="tenant-name">{tenant.name}</div>
                    <div className="tenant-id">Tenant ID: {tenant.id}</div>
                  </div>

                  <div className="tenant-actions">
                    <button
                      className="btn btn-ghost"
                      onClick={() => setTenantId(String(tenant.id))}
                    >
                      Switch
                    </button>

                    <button
                      className="btn btn-ghost"
                      onClick={() => {
                        setEditingTenant(tenant);
                        setShowTenantModal(true);
                      }}
                    >
                      Edit
                    </button>

                    <button
                      className="btn btn-danger"
                      onClick={() => handleDeleteTenant(tenant)}
                    >
                      Delete
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </section>
      </div>

      {showTenantModal && (
        <Modal
          onClose={() => {
            setShowTenantModal(false);
            setEditingTenant(null);
          }}
        >
          <TenantForm
            tenant={editingTenant}
            onSuccess={() => {
              fetchTenants();
              setShowTenantModal(false);
              setEditingTenant(null);
            }}
          />
        </Modal>
      )}

      {showAssetModal && (
        <Modal
          onClose={() => {
            setShowAssetModal(false);
            setEditingAsset(null);
          }}
        >
          <AssetForm
            tenantId={tenantId}
            asset={editingAsset}
            onSuccess={() => {
              fetchAssets();
              setShowAssetModal(false);
              setEditingAsset(null);
            }}
          />
        </Modal>
      )}

      {showIncidentModal && (
        <Modal
          onClose={() => {
            setShowIncidentModal(false);
            setEditingIncident(null);
          }}
        >
          <IncidentForm
            tenantId={tenantId}
            incident={editingIncident}
            assets={assets}
            onSuccess={() => {
              fetchIncidents();
              setShowIncidentModal(false);
              setEditingIncident(null);
            }}
          />
        </Modal>
      )}
    </div>
  );
}

export default App;
